import { db } from "./firebase";
import { ref, push, set, onValue, update, remove, query, orderByChild, equalTo } from "firebase/database";
import { Notification } from "@/types";

const COLLECTION_NAME = "notifications";

export const createNotification = async (notification: Omit<Notification, 'id' | 'createdAt' | 'read'>) => {
    try {
        const notificationsRef = ref(db, COLLECTION_NAME);
        const newNotificationRef = push(notificationsRef);

        const newNotification: Notification = {
            ...notification,
            id: newNotificationRef.key!,
            read: false,
            createdAt: new Date().toISOString()
        };

        await set(newNotificationRef, newNotification);
        return newNotificationRef.key;
    } catch (error) {
        console.error("Error creating notification:", error);
        throw error;
    }
};

export const subscribeToNotifications = (userId: string, callback: (notifications: Notification[]) => void) => {
    const notificationsRef = ref(db, COLLECTION_NAME);
    const userNotificationsQuery = query(
        notificationsRef,
        orderByChild('userId'),
        equalTo(userId)
    );

    return onValue(userNotificationsQuery, (snapshot) => {
        if (snapshot.exists()) {
            const data = snapshot.val();
            const notificationsList = Object.values(data) as Notification[];
            // Sort by descending date
            notificationsList.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            callback(notificationsList);
        } else {
            callback([]);
        }
    });
};

export const markNotificationAsRead = async (notificationId: string) => {
    try {
        const notificationRef = ref(db, `${COLLECTION_NAME}/${notificationId}`);
        await update(notificationRef, { read: true });
    } catch (error) {
        console.error("Error marking notification as read:", error);
    }
};

export const markAllAsRead = async (userId: string, notifications: Notification[]) => {
    try {
        const unread = notifications.filter(n => !n.read);
        const updates: any = {};
        unread.forEach(n => {
            updates[`${COLLECTION_NAME}/${n.id}/read`] = true;
        });
        await update(ref(db), updates);
    } catch (error) {
        console.error("Error marking all notifications as read:", error);
    }
};

export const clearNotifications = async (userId: string, notifications: Notification[]) => {
    try {
        const updates: any = {};
        notifications.forEach(n => {
            updates[`${COLLECTION_NAME}/${n.id}`] = null;
        });
        await update(ref(db), updates);
    } catch (error) {
        console.error("Error clearing notifications:", error);
    }
};
